// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./ICredential.sol";
import "./IRegistry.sol";

/// @title CredentialContract
/// @notice Issues, revokes, and verifies academic credentials via keccak256 hashes.
/// @dev Raw credential data is never stored on-chain. Only hashes are recorded.
contract CredentialContract is ICredential {
    // -------------------------------------------------------------------------
    // Types
    // -------------------------------------------------------------------------

    struct Credential {
        bytes32 credentialHash; // keccak256 of off-chain credential data
        address issuer;
        address holder;
        bool revoked;
        uint256 issuedAt;
    }

    // -------------------------------------------------------------------------
    // State
    // -------------------------------------------------------------------------

    IRegistry public immutable registry;

    /// @dev credentialHash => Credential
    mapping(bytes32 => Credential) private credentials;

    /// @dev credentialHash => verifier address => allowed
    mapping(bytes32 => mapping(address => bool)) private verifierAccess;

    // -------------------------------------------------------------------------
    // Errors
    // -------------------------------------------------------------------------

    error NotAuthorizedIssuer();
    error NotCredentialIssuer();
    error NotCredentialHolder();
    error CredentialAlreadyExists(bytes32 credentialHash);
    error CredentialNotFound(bytes32 credentialHash);
    error CredentialAlreadyRevoked(bytes32 credentialHash);
    error ZeroAddress();

    // -------------------------------------------------------------------------
    // Constructor
    // -------------------------------------------------------------------------

    /// @param registryAddress Address of the deployed RegistryContract.
    constructor(address registryAddress) {
        if (registryAddress == address(0)) revert ZeroAddress();
        registry = IRegistry(registryAddress);
    }

    // -------------------------------------------------------------------------
    // Issuer functions
    // -------------------------------------------------------------------------

    /// @inheritdoc ICredential
    function issueCredential(address holder, bytes32 credentialHash) external override {
        if (!registry.isRegisteredIssuer(msg.sender)) revert NotAuthorizedIssuer();
        if (holder == address(0)) revert ZeroAddress();
        if (credentials[credentialHash].issuedAt != 0) revert CredentialAlreadyExists(credentialHash);

        credentials[credentialHash] = Credential({
            credentialHash: credentialHash,
            issuer: msg.sender,
            holder: holder,
            revoked: false,
            issuedAt: block.timestamp
        });

        emit CredentialIssued(credentialHash, msg.sender, holder);
    }

    /// @inheritdoc ICredential
    function revokeCredential(bytes32 credentialHash) external override {
        Credential storage cred = _requireExists(credentialHash);
        if (cred.issuer != msg.sender) revert NotCredentialIssuer();
        if (cred.revoked) revert CredentialAlreadyRevoked(credentialHash);

        cred.revoked = true;

        emit CredentialRevoked(credentialHash, msg.sender);
    }

    // -------------------------------------------------------------------------
    // Holder functions
    // -------------------------------------------------------------------------

    /// @inheritdoc ICredential
    function grantVerifierAccess(bytes32 credentialHash, address verifier) external override {
        Credential storage cred = _requireExists(credentialHash);
        if (cred.holder != msg.sender) revert NotCredentialHolder();
        if (verifier == address(0)) revert ZeroAddress();

        verifierAccess[credentialHash][verifier] = true;

        emit VerifierAccessGranted(credentialHash, msg.sender, verifier);
    }

    /// @inheritdoc ICredential
    function revokeVerifierAccess(bytes32 credentialHash, address verifier) external override {
        Credential storage cred = _requireExists(credentialHash);
        if (cred.holder != msg.sender) revert NotCredentialHolder();
        if (verifier == address(0)) revert ZeroAddress();

        verifierAccess[credentialHash][verifier] = false;

        emit VerifierAccessRevoked(credentialHash, msg.sender, verifier);
    }

    // -------------------------------------------------------------------------
    // View functions
    // -------------------------------------------------------------------------

    /// @inheritdoc ICredential
    function verifyCredential(bytes32 credentialHash) external view override returns (bool valid, string memory reason) {
        Credential storage cred = credentials[credentialHash];

        if (cred.issuedAt == 0) {
            return (false, "Credential not found");
        }

        if (!registry.isRegisteredIssuer(cred.issuer)) {
            return (false, "Issuer no longer registered");
        }

        if (cred.revoked) {
            return (false, "Credential revoked");
        }

        if (!verifierAccess[credentialHash][msg.sender]) {
            return (false, "Caller not in verifier allowlist");
        }

        return (true, "");
    }

    // -------------------------------------------------------------------------
    // Internal helpers
    // -------------------------------------------------------------------------

    function _requireExists(bytes32 credentialHash) internal view returns (Credential storage) {
        Credential storage cred = credentials[credentialHash];
        if (cred.issuedAt == 0) revert CredentialNotFound(credentialHash);
        return cred;
    }
}

contracts/ICredential.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title ICredential
/// @notice Interface for issuing, revoking, and verifying credentials on-chain.
/// @dev Only keccak256 hashes are stored. Raw credential data must remain off-chain.
interface ICredential {
    // -------------------------------------------------------------------------
    // Events
    // -------------------------------------------------------------------------

    /// @notice Emitted when a credential is issued.
    event CredentialIssued(
        bytes32 indexed credentialHash,
        address indexed issuer,
        address indexed holder
    );

    /// @notice Emitted when a credential is revoked by its issuer.
    event CredentialRevoked(
        bytes32 indexed credentialHash,
        address indexed issuer
    );

    /// @notice Emitted when a holder grants a verifier access to a credential.
    event VerifierAccessGranted(
        bytes32 indexed credentialHash,
        address indexed holder,
        address indexed verifier
    );

    /// @notice Emitted when a holder revokes a verifier's access to a credential.
    event VerifierAccessRevoked(
        bytes32 indexed credentialHash,
        address indexed holder,
        address indexed verifier
    );

    // -------------------------------------------------------------------------
    // Issuer functions
    // -------------------------------------------------------------------------

    /// @notice Issue a credential. Caller must be an authorized issuer.
    /// @param holder Address of the credential holder.
    /// @param credentialHash keccak256 hash of off-chain credential data.
    function issueCredential(address holder, bytes32 credentialHash) external;

    /// @notice Revoke a credential. Caller must be the original issuer.
    /// @param credentialHash Hash of the credential to revoke.
    function revokeCredential(bytes32 credentialHash) external;

    // -------------------------------------------------------------------------
    // Holder functions
    // -------------------------------------------------------------------------

    /// @notice Grant a verifier access to a credential. Caller must be the holder.
    /// @param credentialHash Hash of the credential.
    /// @param verifier Address to grant access to.
    function grantVerifierAccess(bytes32 credentialHash, address verifier) external;

    /// @notice Revoke a verifier's access to a credential. Caller must be the holder.
    /// @param credentialHash Hash of the credential.
    /// @param verifier Address to revoke access from.
    function revokeVerifierAccess(bytes32 credentialHash, address verifier) external;

    // -------------------------------------------------------------------------
    // View functions
    // -------------------------------------------------------------------------

    /// @notice Verify a credential. Caller is the verifier.
    /// @dev Checks four conditions in order:
    ///      1. Credential exists (hash known)
    ///      2. Original issuer is still a registered issuer
    ///      3. Credential has not been revoked
    ///      4. msg.sender is in the holder's verifier allowlist
    /// @param credentialHash Hash of the credential to verify.
    /// @return valid  True if all four conditions pass.
    /// @return reason Human-readable failure reason; empty string on success.
    function verifyCredential(bytes32 credentialHash) external view returns (bool valid, string memory reason);
}

contracts/IRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title IRegistry
/// @notice Interface for managing authorized credential issuers.
interface IRegistry {
    // -------------------------------------------------------------------------
    // Events
    // -------------------------------------------------------------------------

    /// @notice Emitted when an issuer is registered.
    event IssuerAdded(address indexed issuer);

    /// @notice Emitted when an issuer's registration is revoked.
    event IssuerRemoved(address indexed issuer);

    // -------------------------------------------------------------------------
    // Functions
    // -------------------------------------------------------------------------

    /// @notice Register an issuer address. Owner only.
    /// @param issuer Address to register.
    function registerIssuer(address issuer) external;

    /// @notice Revoke an issuer's registration. Owner only.
    /// @param issuer Address to deregister.
    function revokeIssuer(address issuer) external;

    /// @notice Check whether an address is a registered issuer.
    /// @param issuer Address to query.
    /// @return True if registered.
    function isRegisteredIssuer(address issuer) external view returns (bool);
}

